#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005;
ll t,n,m,num[65],vis[N],xornum[N];
ll fun(ll x)
{
	ll xx=x;
	for(int i=59;i>=0;i--)
	{
		if(!(xx&((ll)1<<i)))
		{
			if(num[i])
			{
				xx^=num[i];
			}
		}
	}
	return xx;
}
void insert(ll x)
{
	for(int j=59;j>=0;j--)
	{
		if(x&((ll)1<<j))
		{
			if(num[j])
			{
				x^=num[j];
			}
			else
			{
				num[j]=x;
				break; 
			}
		}
	}
}
struct node
{
	ll v,w;
};
vector<node> g[N];
void dfs(int u,ll now)
{
	xornum[u]=now,vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		ll v=g[u][i].v,w=g[u][i].w;
		if(vis[v]) insert(now^w^xornum[v]);
		else dfs(v,now^w);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout)
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		ll u,v,w;
		cin>>u>>v>>w;
		g[u].push_back(node{v,w});
		g[v].push_back(node{u,w});
	}
	dfs(1,0);
	cout<<fun(xornum[n]);
	return 0;
}
